mapper.update:
UPDATE AP_APPROVAL_LINE SET LINE_STS='SKIP'
 WHERE APRV_ID=#{aprvId} AND STEP_NO > #{afterStepNo}
   AND LINE_TYP IN ('APRV','AGRE') AND LINE_STS IN ('WAIT','ING')

mapper.select:
SELECT L.ID, L.APRV_ID, L.STEP_NO, L.APRV_USR_ID, L.APRV_USR_NM, L.LINE_TYP, T.CD_NM_KO AS LINE_TYP_NM, L.FINAL_YN, L.LINE_STS, LC.CD_NM_KO AS LINE_STS_NM, TO_CHAR(L.APRV_DT,'YYYY-MM-DD HH24:MI') AS APRV_DT, L.OPINION, A.APRV_NO, A.DOC_TYP, A.DOC_ID, A.DOC_NO, A.APRV_TITLE, A.DRAFT_USR_NM FROM AP_APPROVAL_LINE L JOIN AP_APPROVAL A ON A.ID = L.APRV_ID AND A.DEL_YN='N' LEFT JOIN CM_CODE LC ON LC.GRP_CD='LINE_STS' AND LC.CD=L.LINE_STS AND LC.DEL_YN='N' LEFT JOIN CM_CODE T ON T.GRP_CD='AP_LINE_TYP' AND T.CD=L.LINE_TYP AND T.DEL_YN='N' WHERE L.APRV_USR_ID IN #{d}
AND L.LINE_STS IN ('APPROVE','AGREE','FINAL','REJECT') AND L.LINE_STS='ING' AND A.APRV_STS='ING'
ORDER BY L.APRV_ID DESC
